package com.arkeomag.pro; import android.graphics.*;
public class Palette{static int color(float v){v=Math.max(0,Math.min(1,v)); if(v<.25f)return mix(Color.rgb(10,80,220),Color.rgb(0,210,255),v/.25f); if(v<.5f)return mix(Color.rgb(0,210,255),Color.rgb(0,220,95),(v-.25f)/.25f); if(v<.75f)return mix(Color.rgb(0,220,95),Color.rgb(255,210,0),(v-.5f)/.25f); return mix(Color.rgb(255,210,0),Color.rgb(255,40,40),(v-.75f)/.25f);} static int mix(int a,int b,float t){return Color.rgb((int)(Color.red(a)+(Color.red(b)-Color.red(a))*t),(int)(Color.green(a)+(Color.green(b)-Color.green(a))*t),(int)(Color.blue(a)+(Color.blue(b)-Color.blue(a))*t));}}
